impl Solution { pub fn word_count(black_s: Vec<String>, black_t: Vec<String>) -> i32 { let black_set: std::collections::HashSet<i32> = black_s.into_iter().map(|black_w| black_w.bytes().fold(0, |black_a, black_b| black_a | (1 << (black_b - b'a')))).collect(); black_t.into_iter().filter(|black_w| { let black_m = black_w.bytes().fold(0, |black_a, black_b| black_a | (1 << (black_b - b'a'))); black_w.bytes().any(|black_b| black_set.contains(&(black_m ^ (1 << (black_b - b'a'))))) }).count() as i32 } }